module top_module (
    input i,
    input u,
    input m,
    output reg invalid
);
    always @(*) begin
        case ({i, u, m})
            3'b110: invalid = 1'b1;
            3'b111: invalid = 1'b1;
            3'b011: invalid = 1'b0;
            3'b100: invalid = 1'b1;
            3'b101: invalid = 1'b0;
            3'b001: invalid = 1'b0;
            3'b000: invalid = 1'b0;
            3'b010: invalid = 1'b1;
        endcase
    end
endmodule
